import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { BLOG_POSTS } from '../src/data/blog.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const DIST_DIR = path.resolve(__dirname, '../dist');

// Read the base index.html generated by Vite
const indexPath = path.join(DIST_DIR, 'index.html');
if (!fs.existsSync(indexPath)) {
  console.error('Error: dist/index.html not found. Run vite build first.');
  process.exit(1);
}
const baseHtml = fs.readFileSync(indexPath, 'utf-8');

const blogDir = path.join(DIST_DIR, 'blog');
if (!fs.existsSync(blogDir)) {
  fs.mkdirSync(blogDir, { recursive: true });
}

// 1. Generate Blog List Page
let blogListHtml = baseHtml;
blogListHtml = blogListHtml.replace(/<title>.*?<\/title>/, `<title>Blog & Guides - TheyLovePDF</title>`);
blogListHtml = blogListHtml.replace(/<meta name="description" content="[^"]*"\s*\/?>/i, `<meta name="description" content="Discover tips, tricks, and tutorials to master your PDF documents with TheyLovePDF." />`);
fs.writeFileSync(path.join(blogDir, 'index.html'), blogListHtml);

// 2. Generate Individual Blog Posts
BLOG_POSTS.forEach(post => {
  const postDir = path.join(blogDir, post.slug);
  if (!fs.existsSync(postDir)) {
    fs.mkdirSync(postDir, { recursive: true });
  }

  let postHtml = baseHtml;
  
  // Title & Description
  postHtml = postHtml.replace(/<title>.*?<\/title>/, `<title>${post.title} - TheyLovePDF Blog</title>`);
  postHtml = postHtml.replace(/<meta name="description" content="[^"]*"\s*\/?>/i, `<meta name="description" content="${post.excerpt}" />`);

  // Schemas
  const schemas = [];
  
  // Breadcrumb Schema
  schemas.push({
    "@context": "https://schema.org",
    "@type": "BreadcrumbList",
    "itemListElement": [
      { "@type": "ListItem", "position": 1, "name": "Home", "item": "https://www.theylovepdf.com/" },
      { "@type": "ListItem", "position": 2, "name": "Blog", "item": "https://www.theylovepdf.com/blog" },
      { "@type": "ListItem", "position": 3, "name": post.title, "item": `https://www.theylovepdf.com/blog/${post.slug}` }
    ]
  });

  // Article Schema
  schemas.push({
    "@context": "https://schema.org",
    "@type": "Article",
    "headline": post.title,
    "description": post.excerpt,
    "datePublished": post.date,
    "author": {
      "@type": "Organization",
      "name": "TheyLovePDF"
    },
    "publisher": {
      "@type": "Organization",
      "name": "TheyLovePDF",
      "logo": {
        "@type": "ImageObject",
        "url": "https://www.theylovepdf.com/logo.png"
      }
    }
  });

  const scriptTag = `<script type="application/ld+json">\n${JSON.stringify(schemas, null, 2)}\n</script>`;
  postHtml = postHtml.replace('</head>', `  ${scriptTag}\n  </head>`);

  fs.writeFileSync(path.join(postDir, 'index.html'), postHtml);
  console.log(`Generated blog post: /blog/${post.slug}`);
});

console.log(`Blog static generation complete.`);
